"use client";

import { useState } from "react";
import { Icon } from "@/components/shared/icon";
import { StatusBadge } from "@/components/shared/status-badge";
import { TaskFlowPreview } from "@/components/tasks/task-flow-preview";
import { TaskHistoryPanel } from "@/components/tasks/task-history-panel";
import { TaskIntakePanel } from "@/components/tasks/task-intake-panel";
import type { TaskCenterData, TaskCenterViewState } from "@/lib/types";

type TaskCenterPageProps = {
  data: TaskCenterData;
};

const uploadStatusMeta = {
  parsed: {
    label: "已解析",
    className: "border-emerald-400/16 bg-emerald-400/8 text-emerald-100",
  },
  uploading: {
    label: "上传中",
    className: "border-amber-400/16 bg-amber-400/8 text-amber-100",
  },
  failed: {
    label: "失败",
    className: "border-rose-400/16 bg-rose-400/8 text-rose-100",
  },
} as const;

export function TaskCenterPage({ data }: TaskCenterPageProps) {
  const [draftValue, setDraftValue] = useState(data.draftInput);
  const [viewState, setViewState] = useState<TaskCenterViewState>("default");
  const snapshot = data.stateSnapshots[viewState];

  function handlePresetSelect(value: string) {
    setDraftValue(value);
    if (viewState === "empty") {
      setViewState("default");
    }
  }

  return (
    <div className="space-y-6">
      <section className="panel-highlight rounded-[32px] p-6 sm:p-8">
        <div className="grid gap-6 xl:grid-cols-[1.12fr_0.88fr]">
          <div>
            <span className="inline-flex items-center gap-2 rounded-full border border-cyan-400/16 bg-cyan-400/8 px-3 py-1 text-xs font-semibold uppercase tracking-[0.18em] text-cyan-200">
              <Icon name="tasks" className="h-3.5 w-3.5" />
              Unified Task Intake
            </span>
            <h1 className="mt-5 max-w-3xl text-3xl font-semibold tracking-tight text-white sm:text-4xl">
              {data.hero.title}
            </h1>
            <p className="mt-4 max-w-2xl text-base leading-7 text-[var(--foreground-muted)]">
              {data.hero.description}
            </p>
          </div>

          <div className="grid gap-3 sm:grid-cols-2 xl:grid-cols-2">
            <div className="rounded-[28px] border border-white/8 bg-black/12 p-4">
              <p className="text-xs uppercase tracking-[0.18em] text-slate-400">当前状态</p>
              <p className="mt-3 text-2xl font-semibold text-white">{snapshot.title}</p>
              <p className="mt-2 text-sm leading-6 text-[var(--foreground-muted)]">
                {snapshot.summary}
              </p>
            </div>
            <div className="rounded-[28px] border border-white/8 bg-black/12 p-4">
              <p className="text-xs uppercase tracking-[0.18em] text-slate-400">任务分流</p>
              <div className="mt-3 flex flex-wrap gap-2">
                {data.recognizedSignals.map((signal) => (
                  <span
                    key={signal.id}
                    className="rounded-full border border-white/10 bg-white/6 px-3 py-1 text-xs text-slate-200"
                  >
                    {signal.label}
                  </span>
                ))}
              </div>
            </div>
            <div className="rounded-[28px] border border-white/8 bg-black/12 p-4">
              <p className="text-xs uppercase tracking-[0.18em] text-slate-400">Agent 协同</p>
              <div className="mt-3 flex flex-wrap gap-2">
                <StatusBadge status="planning" />
                <StatusBadge status="running" />
                <StatusBadge status="validating" />
              </div>
              <p className="mt-3 text-sm leading-6 text-[var(--foreground-muted)]">
                页面强调任务从识别、执行到校验的流动感。
              </p>
            </div>
            <div className="rounded-[28px] border border-white/8 bg-black/12 p-4">
              <p className="text-xs uppercase tracking-[0.18em] text-slate-400">下一步动作</p>
              <p className="mt-3 text-base font-semibold text-white">{snapshot.actionLabel}</p>
              <p className="mt-2 text-sm leading-6 text-[var(--foreground-muted)]">
                当前状态切换仅用于前端演示，后续由接口返回真实结果。
              </p>
            </div>
          </div>
        </div>
      </section>

      <section className="grid gap-6 xl:grid-cols-[1.12fr_0.88fr]">
        <TaskIntakePanel
          value={draftValue}
          onChange={setDraftValue}
          onPresetSelect={handlePresetSelect}
          promptPresets={data.promptPresets}
          acceptedFileTypes={data.acceptedFileTypes}
          recognizedSignals={data.recognizedSignals}
          actionLabel={snapshot.actionLabel}
          previewState={viewState}
        />

        <aside className="space-y-6">
          <article className="panel rounded-[32px] p-6">
            <div className="flex items-center justify-between gap-3">
              <div>
                <p className="text-xs font-semibold uppercase tracking-[0.24em] text-cyan-300/75">
                  Upload Queue
                </p>
                <h2 className="mt-2 text-xl font-semibold text-white">文件上传区</h2>
              </div>
              <Icon name="document" className="h-5 w-5 text-cyan-200" />
            </div>

            <div className="mt-5 space-y-3">
              {data.uploads.map((file) => (
                <div
                  key={file.id}
                  className="rounded-[28px] border border-white/8 bg-white/4 p-4"
                >
                  <div className="flex items-start justify-between gap-3">
                    <div className="min-w-0">
                      <p className="truncate text-sm font-semibold text-white">{file.name}</p>
                      <p className="mt-1 text-xs text-[var(--foreground-muted)]">
                        {file.size} · {file.kind}
                      </p>
                    </div>
                    <span
                      className={`rounded-full border px-2.5 py-1 text-[11px] font-semibold ${uploadStatusMeta[file.status].className}`}
                    >
                      {uploadStatusMeta[file.status].label}
                    </span>
                  </div>
                </div>
              ))}
            </div>
          </article>

          <article className="panel rounded-[32px] p-6">
            <div className="flex items-center justify-between gap-3">
              <div>
                <p className="text-xs font-semibold uppercase tracking-[0.24em] text-cyan-300/75">
                  Routing Notes
                </p>
                <h2 className="mt-2 text-xl font-semibold text-white">任务分流说明</h2>
              </div>
              <Icon name="trend" className="h-5 w-5 text-cyan-200" />
            </div>
            <div className="mt-5 space-y-3">
              <div className="rounded-[28px] border border-white/8 bg-white/4 p-4">
                <p className="text-sm font-semibold text-white">优先链路</p>
                <p className="mt-2 text-sm leading-6 text-[var(--foreground-muted)]">
                  当前输入优先进入合同审查链，附带模板文书生成和人工确认节点。
                </p>
              </div>
              <div className="rounded-[28px] border border-white/8 bg-white/4 p-4">
                <p className="text-sm font-semibold text-white">调度策略</p>
                <p className="mt-2 text-sm leading-6 text-[var(--foreground-muted)]">
                  Planner 负责意图归类，Executor 负责底座调用，Validator 负责输出可信度检查。
                </p>
              </div>
            </div>
          </article>
        </aside>
      </section>

      <section className="grid gap-6 xl:grid-cols-[0.9fr_1.1fr]">
        <TaskFlowPreview steps={data.recommendedFlow} services={data.serviceHints} />
        <TaskHistoryPanel
          viewState={viewState}
          onViewStateChange={setViewState}
          snapshot={snapshot}
          templates={data.templates}
          integrationPoints={data.integrationPoints}
        />
      </section>
    </div>
  );
}
